oxy_webhelp_navlinks = {"postgresql_setup-d30753e33430":{"topics":[{"title":"Evaluate PostgreSQL authentication options","shortdesc":"<p class=\"shortdesc\">When adding a PostgreSQL cluster to <span class=\"ph\">RSC<\/span>, it is important to evaluate         the available socket-based method for a PostgreSQL client to verify its identity with the         server.<\/p>","href":"postgresql\/postgresql_eval_auth_options.html","attributes":{"data-id":"postgresql_eval_auth_options"},"menu":{"hasChildren":false},"tocID":"postgresql_eval_auth_options-d30753e33444","topics":[]},{"title":"Configure PostgreSQL clusters","shortdesc":"<p class=\"shortdesc\">Configuring a PostgreSQL cluster involves registering the Linux servers with a Rubrik         cluster, installing RBS, and then manually adding each PostgreSQL cluster to <span class=\"ph\">RSC<\/span> with the required configuration details and credentials.<\/p>","href":"postgresql\/postgresql_cluster_configuration.html","attributes":{"data-id":"postgresql_cluster_configuration"},"menu":{"hasChildren":false},"tocID":"postgresql_cluster_configuration-d30753e33458","next":"postgresql_cluster_configuration-d30753e33458"},{"title":"Rubrik cloud cluster elastic storage for PostgreSQL","shortdesc":"<p class=\"shortdesc\">Rubrik Cloud Cluster Elastic Storage is a cloud-native Rubrik deployment model that         protects PostgreSQL workloads running on virtual instances within a Virtual Private Cloud in         public cloud environments.<\/p>","href":"postgresql\/postgresql_rbk_cloud_cluster_elastic_storage.html","attributes":{"data-id":"postgresql_rbk_cloud_cluster_elastic_storage"},"menu":{"hasChildren":false},"tocID":"postgresql_rbk_cloud_cluster_elastic_storage-d30753e33530","topics":[]}]}};